//-----------------------------------------------------------------------------
// MRFProcessToolsDlg : Build
//-----------------------------------------------------------------------------
void MRFProcessToolsDlg::Build()
{

	_pSelectorListFrame = new CATDlgFrame(_pMainFrame, (const char*)"Selector_List_Frame", 0 | CATDlgFraNoTitle | CATDlgGridLayout);
	_pSelectorListFrame->SetGridConstraints(0, 0, 20, 1, CATGRID_4SIDES);

	if (_pSelectorListFrame)
	{
		_pLabelProcessToolGeomSet = new CATDlgLabel(_pSelectorListFrame, (const char*)"Label_ProcessTool2DLayout_Geom_Set", 0 | CATDlgLabLeft);
		_pLabelProcessToolGeomSet->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

		_pSelListProcessToolGeomSet = new CATDlgSelectorList(_pSelectorListFrame, (const char*)"SelList_ProcessTool_Geom_Set", 0);
		_pSelListProcessToolGeomSet->SetGridConstraints(0, 1, 1, 1, CATGRID_4SIDES);
		_pSelListProcessToolGeomSet->SetVisibleTextHeight(1);
		_pSelListProcessToolGeomSet->SetVisibleTextWidth(20);
		_pSelListProcessToolGeomSet->SetLine("No Geom Set Selected");
		_pSelListProcessToolGeomSet->SetSensitivity(CATDlgDisable);

		_pLabelXYPlane = new CATDlgLabel(_pSelectorListFrame, (const char*)"Label_XY_Plane", 0 | CATDlgLabLeft);
		_pLabelXYPlane->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

		_pSelListXYPlane = new CATDlgSelectorList(_pSelectorListFrame, (const char*)"SelList_XYPlane", 0);
		_pSelListXYPlane->SetGridConstraints(1, 1, 1, 1, CATGRID_4SIDES);
		_pSelListXYPlane->SetVisibleTextHeight(1);
		_pSelListXYPlane->SetVisibleTextWidth(20);
		_pSelListXYPlane->SetLine("No Plane Selected");
	}


	_pTabFrame = new CATDlgFrame(_pMainFrame, (const char*)"TabFrame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame| CATDlgGridLayout);
	_pTabFrame->SetGridConstraints(1, 0, 20, 1, CATGRID_4SIDES);

	if (_pTabFrame)
	{
		_pTabContainer = new CATDlgTabContainer(_pTabFrame, (const char*)"TabContainer", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame |CATDlgGridLayout);
		_pTabContainer->SetGridConstraints(0, 0, 20, 1, CATGRID_4SIDES);

	}

	_pPushButtonPrevTab = new CATDlgPushButton(_pMainFrame, (const char*)"Prev_Tab", 0);
	_pPushButtonPrevTab->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);


	_pPushButtonUpdate = new CATDlgPushButton(_pMainFrame, (const char*)"Update", 0);
	_pPushButtonUpdate->SetGridConstraints(3, 1, 1, 1, CATGRID_4SIDES);

	_pPushButtonNextTab = new CATDlgPushButton(_pMainFrame, (const char*)"Next_Tab", 0);
	_pPushButtonNextTab->SetGridConstraints(3, 2, 4, 1, CATGRID_4SIDES);


}

//-----------------------------------------------------------------------------
// MRFProcessToolsDlg : ClearOtherSelections
// Clears other selections upon selection of an item
//-----------------------------------------------------------------------------
void MRFProcessToolsDlg::ClearOtherSelections(CATString strAction)
{
	if (strAction == FromProcessGeomSetSelector)
	{
		if (_pSelListXYPlane)
			_pSelListXYPlane->ClearSelect();
	}
	else if (strAction == FromProcessXYPlaneSelector)
	{
		if (_pSelListProcessToolGeomSet)
			_pSelListProcessToolGeomSet->ClearSelect();
		
	}

}
//-----------------------------------------------------------------------------
// MRFProcessToolsDlg : UpdateSelectorList
// Updates the selector list based on the value string to set
//-----------------------------------------------------------------------------
void MRFProcessToolsDlg::UpdateSelectorList(CATString strAction, CATUnicodeString aliasNameToSet)
{
	CATDlgSelectorList *pSelectorList_actual = NULL, *pSelectorListNext = NULL;
	if (strAction == FromProcessGeomSetSelector)
	{
		pSelectorList_actual = _pSelListProcessToolGeomSet;
		pSelectorListNext = _pSelListXYPlane;
	}
	else if (strAction == FromProcessXYPlaneSelector)
	{
		pSelectorList_actual = _pSelListXYPlane;
	}
	
	if (pSelectorList_actual)
	{
		pSelectorList_actual->ClearLine();
		pSelectorList_actual->SetLine(aliasNameToSet);

		int select = 0;
		pSelectorList_actual->SetSelect(&select, 1, 0);
	}

	if (pSelectorListNext)
	{
		int select = 0;
		pSelectorListNext->SetSelect(&select, 1, 1);
	}
}
//-----------------------------------------------------------------------------
// MRFProcessToolsDlg : SetComboBoxValuesReadFromNLS
// Sets Combo box values reading from the NLS file
//-----------------------------------------------------------------------------
void MRFProcessToolsDlg::SetComboBoxValuesReadFromNLS(CATDlgCombo *pComboBox, CATUnicodeString NLSFileName)
{

	if (!pComboBox)
		return;

	CATUnicodeString  profileCountAsStr;
	int UDFCount;
	CATString NLSFileNameLoc = NLSFileName, udfCountName = NLSFileNameLoc + ".UDFCount";

	profileCountAsStr = CATMsgCatalog::BuildMessage(NLSFileNameLoc, udfCountName);
	profileCountAsStr.ConvertToNum(&UDFCount, "%d");

	CATUnicodeString UDFNameListLines[100], udfName;
	bool atleatOneProfileFound = false;

	int UDFFound_Count = 0;
	for (int i = 1; i <= UDFCount; i++)
	{
		CATString NLSFileNameLocal = NLSFileName;

		CATString profileName = NLSFileNameLocal + ".UDF.";

		CATUnicodeString CountAsStr;
		CountAsStr.BuildFromNum(i);
		profileName.Append(CountAsStr.ConvertToChar());
		profileName.Append(".Name");

		udfName = CATMsgCatalog::BuildMessage(NLSFileNameLoc, profileName);
		if (!udfName.Compare(""))
		{
			UDFNameListLines[i - 1] = udfName;
			atleatOneProfileFound = true;
			UDFFound_Count++;
		}
	}

	/*for (int j = 0; j < profileCount; j++)
	{
		CATString sKey;
		CATUnicodeString usText;
		sprintf(bufferName_key, "MRFTWIMarkingCmd.UDFName.Profile_%d", j);
		sKey = bufferName_key;
		if (0 != _pMRFTWIMarkingDlg->GetResourceValueFromKey(sKey, usText))
		{
			UDFNameListLines[j] = usText;
			atleatOneProfileFound = true;
		}
	}*/

	if (atleatOneProfileFound)
		pComboBox->SetLine(UDFNameListLines, UDFFound_Count);
}
